func (l *Launcher) LaunchClaudeCode(r *http.Request, request LaunchRequest) (LaunchResult, error) {
	startedAt := time.Now().UTC()
	command := strings.TrimSpace(request.Command)
	if command == "" {
		command = "claude"
	}
	workingDir := strings.TrimSpace(request.WorkingDir)
	if workingDir == "" {
		if cwd, err := os.Getwd(); err == nil {
			workingDir = cwd
		}
	}
	sessionTitle := strings.TrimSpace(request.SessionTitle)
	if sessionTitle == "" {
		sessionTitle = "Claude Code launch " + startedAt.Format("2006-01-02 15:04:05")
	}
	clientProfile := strings.TrimSpace(l.ClientProfile)
	if clientProfile == "" {
		clientProfile = "claude-code"
	}
	mode := strings.ToLower(strings.TrimSpace(request.Mode))
	if mode == "" {
		mode = "reverse"
	}
	if mode != "reverse" {
		return LaunchResult{}, fmt.Errorf("unsupported launch mode %q; only reverse is currently supported from the viewer", mode)
	}
	upstream := strings.TrimSpace(request.Upstream)
	if upstream == "" {
		upstream = "https://api.anthropic.com"
	}
	if err := validateHTTPURL(upstream); err != nil {
		return LaunchResult{}, err
	}
	baseURL := requestBaseURL(r)

	runID, sessionID, err := l.createLaunchSession(r, launchSessionInput{
		ClientProfile: clientProfile,
		WorkingDir:    workingDir,
		Command:       strings.Join(append([]string{command}, request.Args...), " "),
		StartedAt:     startedAt,
		SessionTitle:  sessionTitle,
		BaseURL:       baseURL,
		Mode:          mode,
		Upstream:      upstream,
	})
	if err != nil {
		return LaunchResult{}, err
	}
	useTerminal := true
	if request.Terminal != nil {
		useTerminal = *request.Terminal
	}
	pid, status, err := launchCommand(command, request.Args, workingDir, baseURL, useTerminal, l.Logger)
	if err != nil {
		return LaunchResult{}, err
	}
	if l.Session != nil {
		l.Session.SetActiveSessionID(sessionID)
	}
	if l.Upstream != nil {
		l.Upstream.SetActiveUpstream(mode, upstream)
	}
	return LaunchResult{
		SessionID:     sessionID,
		CaptureRunID:  runID,
		Command:       command,
		Args:          request.Args,
		WorkingDir:    workingDir,
		BaseURL:       baseURL,
		Mode:          mode,
		Upstream:      upstream,
		PID:           pid,
		Terminal:      useTerminal,
		Status:        status,
		ActiveSession: true,
	}, nil
}

func (l *Launcher) LaunchCodex(r *http.Request, request LaunchRequest) (LaunchResult, error) {
	startedAt := time.Now().UTC()
	workingDir := strings.TrimSpace(request.WorkingDir)
	if workingDir == "" {
		if cwd, err := os.Getwd(); err == nil {
			workingDir = cwd
		}
	}
	sessionTitle := strings.TrimSpace(request.SessionTitle)
	if sessionTitle == "" {
		sessionTitle = "Codex launch " + startedAt.Format("2006-01-02 15:04:05")
	}
	upstream := strings.TrimSpace(request.Upstream)
	if upstream == "" {
		upstream = "https://chatgpt.com"
	}
	if err := validateHTTPURL(upstream); err != nil {
		return LaunchResult{}, err
	}
	basePath := strings.TrimSpace(request.BasePath)
	if basePath == "" {
		basePath = "/backend-api/codex"
	}
	if !strings.HasPrefix(basePath, "/") {
		basePath = "/" + basePath
	}
	baseURL := requestBaseURL(r)
	configPath := expandHome(strings.TrimSpace(request.ConfigPath))
	if configPath == "" {
		configPath = filepath.Join(userHomeDir(), ".codex", "config.toml")
	}
	appName := strings.TrimSpace(request.AppName)
	if appName == "" {
		appName = "Codex"
	}

	backupPath, err := writeCodexConfig(configPath, baseURL, basePath)
	if err != nil {
		return LaunchResult{}, err
	}

	command := "open"
	args := []string{"-a", appName}
	if workingDir != "" {
		args = append(args, workingDir)
	}
	runID, sessionID, err := l.createLaunchSession(r, launchSessionInput{
		ClientProfile: "codex",
		WorkingDir:    workingDir,
		Command:       strings.Join(append([]string{command}, args...), " "),
		StartedAt:     startedAt,
		SessionTitle:  sessionTitle,
		BaseURL:       baseURL,
		Mode:          "reverse",
		Upstream:      upstream,
		Metadata: map[string]any{
			"base_path":   basePath,
			"config_path": configPath,
			"app_name":    appName,
		},
	})
	if err != nil {
		return LaunchResult{}, err
	}
	if err := exec.Command(command, args...).Start(); err != nil {
		return LaunchResult{}, fmt.Errorf("launch Codex Desktop: %w", err)
	}
	if l.Session != nil {
		l.Session.SetActiveSessionID(sessionID)
	}
	if l.Upstream != nil {
		l.Upstream.SetActiveUpstream("reverse", upstream)
	}
	return LaunchResult{
		SessionID:     sessionID,
		CaptureRunID:  runID,
		Command:       command,
		Args:          args,
		WorkingDir:    workingDir,
		BaseURL:       baseURL,
		Mode:          "reverse",
		Upstream:      upstream,
		BasePath:      basePath,
		ConfigPath:    configPath,
		ConfigBackup:  backupPath,
		Status:        "launched_desktop",
		ActiveSession: true,
	}, nil
}

