func launchCommand(command string, args []string, workingDir string, baseURL string, terminal bool, logger *log.Logger) (int, string, error) {
	if terminal && runtime.GOOS == "darwin" {
		script := terminalScript(command, args, workingDir, baseURL)
		cmd := exec.Command("osascript", "-e", `tell application "Terminal" to do script `+strconv.Quote(script))
		if err := cmd.Run(); err != nil {
			return 0, "", fmt.Errorf("launch Terminal command: %w", err)
		}
		return 0, "launched_terminal", nil
	}

	cmd := exec.Command(command, args...)
	if workingDir != "" {
		cmd.Dir = workingDir
	}
	cmd.Env = append(os.Environ(), "ANTHROPIC_BASE_URL="+baseURL)
	cmd.Stdin = os.Stdin
	cmd.Stdout = os.Stdout
	cmd.Stderr = os.Stderr
	if err := cmd.Start(); err != nil {
		return 0, "", fmt.Errorf("start command: %w", err)
	}
	go func() {
		_ = cmd.Wait()
	}()
	if logger != nil {
		logger.Printf("launched %s pid=%d ANTHROPIC_BASE_URL=%s", command, cmd.Process.Pid, baseURL)
	}
	return cmd.Process.Pid, "started", nil
}

func terminalScript(command string, args []string, workingDir string, baseURL string) string {
	var parts []string
	if workingDir != "" {
		parts = append(parts, "cd "+shellQuote(workingDir))
	}
	parts = append(parts, "export ANTHROPIC_BASE_URL="+shellQuote(baseURL))
	commandParts := []string{shellQuote(command)}
	for _, arg := range args {
		commandParts = append(commandParts, shellQuote(arg))
	}
	parts = append(parts, "exec "+strings.Join(commandParts, " "))
	return strings.Join(parts, " && ")
}

func shellQuote(value string) string {
	return "'" + strings.ReplaceAll(value, "'", "'\"'\"'") + "'"
}

