func (l *Launcher) createLaunchSession(r *http.Request, input launchSessionInput) (string, string, error) {
	metadata := map[string]any{
		"launcher": "viewer",
		"base_url": input.BaseURL,
		"mode":     input.Mode,
		"upstream": input.Upstream,
	}
	for key, value := range input.Metadata {
		metadata[key] = value
	}
	runID, err := l.Store.CreateCaptureRun(r.Context(), store.CaptureRun{
		ClientProfileID: input.ClientProfile,
		WorkingDir:      input.WorkingDir,
		Command:         input.Command,
		StartedAt:       input.StartedAt,
		Metadata:        metadata,
	})
	if err != nil {
		return "", "", err
	}
	sessionID, err := l.Store.CreateSession(r.Context(), store.Session{
		CaptureRunID:    runID,
		ClientProfileID: input.ClientProfile,
		Title:           input.SessionTitle,
		StartedAt:       input.StartedAt,
		Metadata:        metadata,
	})
	if err != nil {
		return "", "", err
	}
	return runID, sessionID, nil
}

func requestBaseURL(r *http.Request) string {
	scheme := "http"
	if r.TLS != nil {
		scheme = "https"
	}
	if forwarded := strings.TrimSpace(r.Header.Get("X-Forwarded-Proto")); forwarded != "" {
		scheme = forwarded
	}
	host := r.Host
	if host == "" {
		host = "127.0.0.1:8787"
	}
	return scheme + "://" + host
}

func validateHTTPURL(raw string) error {
	parsed, err := url.Parse(raw)
	if err != nil {
		return fmt.Errorf("invalid upstream %q: %w", raw, err)
	}
	if parsed.Scheme == "" || parsed.Host == "" {
		return fmt.Errorf("upstream must be an absolute URL")
	}
	if parsed.Scheme != "http" && parsed.Scheme != "https" {
		return fmt.Errorf("upstream scheme must be http or https")
	}
	return nil
}

func writeCodexConfig(configPath string, baseURL string, basePath string) (string, error) {
	if configPath == "" {
		return "", fmt.Errorf("codex config path is required")
	}
	if err := os.MkdirAll(filepath.Dir(configPath), 0o755); err != nil {
		return "", fmt.Errorf("create codex config dir: %w", err)
	}
	payload, err := os.ReadFile(configPath)
	if err != nil && !errors.Is(err, os.ErrNotExist) {
		return "", fmt.Errorf("read codex config: %w", err)
	}
	backupPath := ""
	if err == nil {
		backupPath = fmt.Sprintf("%s.aethertrace.bak.%s", configPath, time.Now().UTC().Format("20060102150405"))
		if err := os.WriteFile(backupPath, payload, 0o600); err != nil {
			return "", fmt.Errorf("backup codex config: %w", err)
		}
	}
	next := rewriteCodexConfig(string(payload), baseURL, basePath)
	if err := os.WriteFile(configPath, []byte(next), 0o600); err != nil {
		return "", fmt.Errorf("write codex config: %w", err)
	}
	return backupPath, nil
}

