+func (l *Launcher) RegisterProcess(process *LaunchProcess) string {
+	if process == nil {
+		return ""
+	}
+	l.processMu.Lock()
+	defer l.processMu.Unlock()
+	if l.processes == nil {
+		l.processes = make(map[string]*LaunchProcess)
+	}
+	if process.ID == "" {
+		process.ID = "launch_" + process.SessionID
+	}
+	l.processes[process.ID] = process
+	if process.cmd != nil {
+		go l.waitForProcess(process.ID, process.cmd)
+	}
+	return process.ID
+}
+
+func (l *Launcher) waitForProcess(id string, cmd *exec.Cmd) {
+	err := cmd.Wait()
+	exitedAt := time.Now().UTC().Format(time.RFC3339)
+	status := "exited"
+	errorText := ""
+	var exitCode *int
+	if err != nil {
+		status = "failed"
+		errorText = err.Error()
+		if exitErr, ok := err.(*exec.ExitError); ok {
+			code := exitErr.ExitCode()
+			exitCode = &code
+			if code == 130 || code == 143 {
+				status = "stopped"
+			}
+		}
+	} else if cmd.ProcessState != nil {
+		code := cmd.ProcessState.ExitCode()
+		exitCode = &code
+	}
+	l.processMu.Lock()
+	defer l.processMu.Unlock()
+	if process, ok := l.processes[id]; ok {
+		process.Status = status
+		process.ExitedAt = exitedAt
+		process.ExitCode = exitCode
+		process.Error = errorText
+		process.StopSupported = false
+	}
+}
+
+func (l *Launcher) ListProcesses() []LaunchProcess {
+	l.processMu.Lock()
+	defer l.processMu.Unlock()
+	processes := make([]LaunchProcess, 0, len(l.processes))
+	for _, process := range l.processes {
+		copy := *process
+		copy.cmd = nil
+		processes = append(processes, copy)
+	}
+	sort.Slice(processes, func(i, j int) bool {
+		return processes[i].StartedAt > processes[j].StartedAt
+	})
+	return processes
+}
+
+func (l *Launcher) StopProcess(id string) (LaunchProcess, error) {
+	l.processMu.Lock()
+	process, ok := l.processes[id]
+	if !ok {
+		l.processMu.Unlock()
+		return LaunchProcess{}, fmt.Errorf("launch process %q not found", id)
+	}
+	if process.cmd == nil || process.cmd.Process == nil || !process.StopSupported {
+		copy := *process
+		copy.cmd = nil
+		l.processMu.Unlock()
+		return copy, fmt.Errorf("launch process %q cannot be stopped from Aethertrace", id)
+	}
+	process.Status = "stopping"
+	cmd := process.cmd
+	l.processMu.Unlock()
+
+	if err := cmd.Process.Signal(os.Interrupt); err != nil {
+		return LaunchProcess{}, fmt.Errorf("stop launch process %q: %w", id, err)
+	}
+	l.processMu.Lock()
+	defer l.processMu.Unlock()
+	copy := *l.processes[id]
+	copy.cmd = nil
+	return copy, nil
