+func (h *Handler) serveLocalFile(w http.ResponseWriter, r *http.Request) {
+	if r.Method != http.MethodGet && r.Method != http.MethodHead {
+		writeJSONError(w, http.StatusMethodNotAllowed, fmt.Errorf("method not allowed"))
+		return
+	}
+	path := strings.TrimSpace(r.URL.Query().Get("path"))
+	if path == "" || !filepath.IsAbs(path) {
+		writeJSONError(w, http.StatusBadRequest, fmt.Errorf("local file path must be absolute"))
+		return
+	}
+	cleanPath := filepath.Clean(path)
+	if !isAllowedImagePath(cleanPath) {
+		writeJSONError(w, http.StatusBadRequest, fmt.Errorf("unsupported local image type"))
+		return
+	}
+	info, err := os.Stat(cleanPath)
+	if err != nil {
+		status := http.StatusInternalServerError
+		if errors.Is(err, os.ErrNotExist) {
+			status = http.StatusNotFound
+		}
+		writeJSONError(w, status, err)
+		return
+	}
+	if info.IsDir() {
+		writeJSONError(w, http.StatusBadRequest, fmt.Errorf("local file path is a directory"))
+		return
+	}
+	if info.Size() > 25*1024*1024 {
+		writeJSONError(w, http.StatusRequestEntityTooLarge, fmt.Errorf("local image is too large"))
+		return
+	}
+	file, err := os.Open(cleanPath)
+	if err != nil {
+		writeJSONError(w, http.StatusInternalServerError, err)
+		return
+	}
+	defer file.Close()
+
+	var sniff [512]byte
+	n, _ := io.ReadFull(file, sniff[:])
+	contentType := http.DetectContentType(sniff[:n])
+	if !strings.HasPrefix(contentType, "image/") {
+		writeJSONError(w, http.StatusBadRequest, fmt.Errorf("local file is not an image"))
+		return
+	}
+	if _, err := file.Seek(0, io.SeekStart); err != nil {
+		writeJSONError(w, http.StatusInternalServerError, err)
+		return
+	}
+	w.Header().Set("Content-Type", contentType)
+	w.Header().Set("Cache-Control", "private, max-age=60")
+	http.ServeContent(w, r, filepath.Base(cleanPath), info.ModTime(), file)
+}
+
+func isAllowedImagePath(path string) bool {
+	switch strings.ToLower(filepath.Ext(path)) {
+	case ".png", ".jpg", ".jpeg", ".gif", ".webp", ".bmp":
+		return true
+	default:
+		return false
+	}
+}
