+func writeCodexConfig(configPath string, baseURL string, basePath string) (string, error) {
+	if configPath == "" {
+		return "", fmt.Errorf("codex config path is required")
+	}
+	if err := os.MkdirAll(filepath.Dir(configPath), 0o755); err != nil {
+		return "", fmt.Errorf("create codex config dir: %w", err)
+	}
+	payload, err := os.ReadFile(configPath)
+	if err != nil && !errors.Is(err, os.ErrNotExist) {
+		return "", fmt.Errorf("read codex config: %w", err)
+	}
+	backupPath := ""
+	if err == nil {
+		backupPath = fmt.Sprintf("%s.aethertrace.bak.%s", configPath, time.Now().UTC().Format("20060102150405"))
+		if err := os.WriteFile(backupPath, payload, 0o600); err != nil {
+			return "", fmt.Errorf("backup codex config: %w", err)
+		}
+	}
+	next := rewriteCodexConfig(string(payload), baseURL, basePath)
+	if err := os.WriteFile(configPath, []byte(next), 0o600); err != nil {
+		return "", fmt.Errorf("write codex config: %w", err)
+	}
+	return backupPath, nil
+}
+
+func rewriteCodexConfig(input string, baseURL string, basePath string) string {
+	var out []string
+	currentSection := ""
+	insertedProvider := false
+	skippingAethertrace := false
+
+	for _, line := range strings.Split(input, "\n") {
+		trimmed := strings.TrimSpace(line)
+		isSection := strings.HasPrefix(trimmed, "[") && strings.Contains(trimmed, "]")
+		sectionName := ""
+		if isSection {
+			sectionName = strings.TrimSpace(strings.TrimSuffix(strings.TrimPrefix(trimmed, "["), "]"))
+		}
+
+		if skippingAethertrace {
+			if isSection {
+				skippingAethertrace = false
+			} else {
+				continue
+			}
+		}
+
+		if sectionName == "model_providers.aethertrace" {
+			skippingAethertrace = true
+			currentSection = sectionName
+			continue
+		}
+		if currentSection == "" && strings.HasPrefix(trimmed, "model_provider") {
+			if !insertedProvider {
+				out = append(out, `model_provider = "aethertrace"`)
+				insertedProvider = true
+			}
+			continue
+		}
+		if isSection {
+			if !insertedProvider {
+				out = append(out, `model_provider = "aethertrace"`)
+				insertedProvider = true
+			}
+			currentSection = sectionName
+		}
+		if trimmed != "" || len(out) > 0 {
+			out = append(out, line)
+		}
+	}
+	if !insertedProvider {
+		out = append([]string{`model_provider = "aethertrace"`}, out...)
+	}
+	for len(out) > 0 && strings.TrimSpace(out[len(out)-1]) == "" {
+		out = out[:len(out)-1]
+	}
+	out = append(out,
+		"",
+		"[model_providers.aethertrace]",
+		`name = "Aethertrace reverse"`,
+		fmt.Sprintf(`base_url = "%s%s"`, strings.TrimRight(baseURL, "/"), basePath),
+		`wire_api = "responses"`,
+		`requires_openai_auth = true`,
+		`supports_websockets = false`,
+	)
+	return strings.Join(out, "\n") + "\n"
+}
+
+func expandHome(path string) string {
+	if path == "" || path == "~" {
+		if path == "~" {
+			return userHomeDir()
+		}
+		return ""
+	}
+	if strings.HasPrefix(path, "~/") {
+		return filepath.Join(userHomeDir(), strings.TrimPrefix(path, "~/"))
+	}
+	return path
+}
+
+func userHomeDir() string {
+	home, err := os.UserHomeDir()
+	if err != nil {
+		return ""
+	}
+	return home
+}
