func rewriteCodexConfig(input string, baseURL string, basePath string) string {
	var out []string
	currentSection := ""
	insertedProvider := false
	skippingAethertrace := false

	for _, line := range strings.Split(input, "\n") {
		trimmed := strings.TrimSpace(line)
		isSection := strings.HasPrefix(trimmed, "[") && strings.Contains(trimmed, "]")
		sectionName := ""
		if isSection {
			sectionName = strings.TrimSpace(strings.TrimSuffix(strings.TrimPrefix(trimmed, "["), "]"))
		}

		if skippingAethertrace {
			if isSection {
				skippingAethertrace = false
			} else {
				continue
			}
		}

		if sectionName == "model_providers.aethertrace" {
			skippingAethertrace = true
			currentSection = sectionName
			continue
		}
		if currentSection == "" && strings.HasPrefix(trimmed, "model_provider") {
			if !insertedProvider {
				out = append(out, `model_provider = "aethertrace"`)
				insertedProvider = true
			}
			continue
		}
		if isSection {
			if !insertedProvider {
				out = append(out, `model_provider = "aethertrace"`)
				insertedProvider = true
			}
			currentSection = sectionName
		}
		if trimmed != "" || len(out) > 0 {
			out = append(out, line)
		}
	}
	if !insertedProvider {
		out = append([]string{`model_provider = "aethertrace"`}, out...)
	}
	for len(out) > 0 && strings.TrimSpace(out[len(out)-1]) == "" {
		out = out[:len(out)-1]
	}
	out = append(out,
		"",
		"[model_providers.aethertrace]",
		`name = "Aethertrace reverse"`,
		fmt.Sprintf(`base_url = "%s%s"`, strings.TrimRight(baseURL, "/"), basePath),
		`wire_api = "responses"`,
		`requires_openai_auth = true`,
		`supports_websockets = false`,
	)
	return strings.Join(out, "\n") + "\n"
}

func expandHome(path string) string {
	if path == "" || path == "~" {
		if path == "~" {
			return userHomeDir()
		}
		return ""
	}
	if strings.HasPrefix(path, "~/") {
		return filepath.Join(userHomeDir(), strings.TrimPrefix(path, "~/"))
	}
	return path
}

func userHomeDir() string {
	home, err := os.UserHomeDir()
	if err != nil {
		return ""
	}
	return home
}

func (l *Launcher) RegisterProcess(process *LaunchProcess) string {
	if process == nil {
		return ""
	}
	l.processMu.Lock()
	defer l.processMu.Unlock()
	if l.processes == nil {
		l.processes = make(map[string]*LaunchProcess)
	}
	if process.ID == "" {
		process.ID = "launch_" + process.SessionID
	}
	l.processes[process.ID] = process
	if process.cmd != nil {
		go l.waitForProcess(process.ID, process.cmd)
	}
	return process.ID
}

func (l *Launcher) waitForProcess(id string, cmd *exec.Cmd) {
	err := cmd.Wait()
	exitedAt := time.Now().UTC().Format(time.RFC3339)
	status := "exited"
	errorText := ""
	var exitCode *int
	if err != nil {
		status = "failed"
		errorText = err.Error()
		if exitErr, ok := err.(*exec.ExitError); ok {
			code := exitErr.ExitCode()
			exitCode = &code
			if code == 130 || code == 143 {
				status = "stopped"
			}
		}
	} else if cmd.ProcessState != nil {
		code := cmd.ProcessState.ExitCode()
		exitCode = &code
	}
	l.processMu.Lock()
	defer l.processMu.Unlock()
	if process, ok := l.processes[id]; ok {
		process.Status = status
		process.ExitedAt = exitedAt
		process.ExitCode = exitCode
		process.Error = errorText
		process.StopSupported = false
	}
}

