func (l *Launcher) StopProcess(id string) (LaunchProcess, error) {
	l.processMu.Lock()
	process, ok := l.processes[id]
	if !ok {
		l.processMu.Unlock()
		return LaunchProcess{}, fmt.Errorf("launch process %q not found", id)
	}
	if process.cmd == nil || process.cmd.Process == nil || !process.StopSupported {
